import React from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastItem[];
}

const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) {
    return '☀️';
  } else if (conditionLower.includes('cloud')) {
    return '☁️';
  } else if (conditionLower.includes('rain') || conditionLower.includes('drizzle')) {
    return '🌧️';
  } else if (conditionLower.includes('snow')) {
    return '❄️';
  } else if (conditionLower.includes('storm') || conditionLower.includes('thunder')) {
    return '⛈️';
  } else if (conditionLower.includes('fog') || conditionLower.includes('mist')) {
    return '🌫️';
  } else if (conditionLower.includes('wind')) {
    return '💨';
  } else if (conditionLower.includes('partly')) {
    return '⛅';
  }
  return '🌤️';
};

export default function GeneratedComponent({
  city = 'Unknown City',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 10,
  unit = '°F',
  forecast = [],
}: Props) {
  return (
    <Card
      padding="24"
      shadow="md"
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header Section */}
        <Stack direction="vertical" gap={8}>
          <Text
            variant="h3"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="bold"
          >
            {city}
          </Text>
        </Stack>

        {/* Current Weather Section */}
        <Stack direction="horizontal" align="center" gap={24}>
          <Stack direction="vertical" align="center" gap={8}>
            <div
              style={{
                fontSize: '64px',
                lineHeight: '1',
              }}
            >
              {getWeatherEmoji(condition)}
            </div>
            <Text
              variant="body"
              color="var(--ggui-color-primary-700, #0369a1)"
              weight="medium"
            >
              {condition}
            </Text>
          </Stack>

          <Stack direction="vertical" gap={4}>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-900, #0c4a6e)',
                lineHeight: '1',
              }}
            >
              {Math.round(temperature)}{unit}
            </div>
          </Stack>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-primary-200, #bae6fd)',
          }}
        />

        {/* Details Section */}
        <Row gap={32} justify="center">
          <Stack direction="vertical" align="center" gap={4}>
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="medium"
            >
              Humidity
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="semibold"
            >
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" align="center" gap={4}>
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="medium"
            >
              Wind Speed
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="semibold"
            >
              {windSpeed} {unit === '°F' ? 'mph' : 'km/h'}
            </Text>
          </Stack>
        </Row>

        {/* Forecast Section */}
        {forecast && forecast.length > 0 && (
          <>
            <div
              style={{
                height: '1px',
                background: 'var(--ggui-color-primary-200, #bae6fd)',
              }}
            />

            <Stack direction="vertical" gap={12}>
              <Text
                variant="label"
                color="var(--ggui-color-primary-800, #075985)"
                weight="semibold"
              >
                5-Day Forecast
              </Text>

              <Row
                gap={8}
                justify="between"
                wrap={true}
                align="center"
                style={{
                  overflow: 'auto',
                  paddingBottom: '4px',
                }}
              >
                {forecast.slice(0, 5).map((day, index) => (
                  <Stack
                    key={index}
                    direction="vertical"
                    align="center"
                    gap={6}
                    style={{
                      padding: 'var(--ggui-spacing-2, 8px)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      background: 'rgba(255, 255, 255, 0.6)',
                      minWidth: '70px',
                      textAlign: 'center',
                    }}
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-primary-700, #0369a1)"
                      weight="semibold"
                    >
                      {day.day}
                    </Text>
                    <div style={{ fontSize: '24px' }}>
                      {day.icon || getWeatherEmoji(day.day)}
                    </div>
                    <Stack direction="horizontal" gap={4}>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-primary-900, #0c4a6e)"
                        weight="medium"
                      >
                        {Math.round(day.high)}°
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        {Math.round(day.low)}°
                      </Text>
                    </Stack>
                  </Stack>
                ))}
              </Row>
            </Stack>
          </>
        )}
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();

  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';

  return '🌤️';
};

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
