import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Box,
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: string;
  forecast?: ForecastItem[];
}

const getWeatherEmoji = (condition: string): string => {
  if (!condition) return '🌤️';

  const cond = condition.toLowerCase();
  if (cond.includes('sunny') || cond.includes('clear')) return '☀️';
  if (cond.includes('cloud')) return '☁️';
  if (cond.includes('rain')) return '🌧️';
  if (cond.includes('snow')) return '❄️';
  if (cond.includes('storm') || cond.includes('thunder')) return '⛈️';
  if (cond.includes('wind')) return '💨';
  if (cond.includes('fog') || cond.includes('mist')) return '🌫️';
  if (cond.includes('hail')) return '🧊';

  return '🌤️';
};

export default function GeneratedComponent(props: Props) {
  const {
    city = 'City',
    temperature = 72,
    condition = 'Partly Cloudy',
    humidity = 65,
    windSpeed = 12,
    unit = '°F',
    forecast = [
      { day: 'Mon', icon: '☀️', high: 75, low: 62 },
      { day: 'Tue', icon: '☁️', high: 73, low: 61 },
      { day: 'Wed', icon: '🌧️', high: 68, low: 58 },
      { day: 'Thu', icon: '⛈️', high: 70, low: 59 },
      { day: 'Fri', icon: '☀️', high: 76, low: 63 },
    ],
  } = props;

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card padding={0} border={false} shadow="none">
      <Stack direction="vertical" gap={0}>
        {/* Main Weather Section */}
        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-700, #0369a1))"
          borderRadius="var(--ggui-shape-radius-md, 8px)"
        >
          <Stack direction="vertical" gap="var(--ggui-spacing-4, 16px)" align="center">
            {/* City and Weather Icon */}
            <Stack direction="vertical" gap="var(--ggui-spacing-2, 8px)" align="center">
              <Text
                variant="body"
                color="rgba(255, 255, 255, 0.9)"
                weight="medium"
              >
                {city}
              </Text>
              <div style={{ fontSize: '56px', lineHeight: '1' }}>
                {weatherEmoji}
              </div>
            </Stack>

            {/* Temperature */}
            <Text
              variant="h1"
              color="white"
              weight="bold"
            >
              {Math.round(temperature)}{unit}
            </Text>

            {/* Condition */}
            <Text
              variant="body"
              color="rgba(255, 255, 255, 0.85)"
            >
              {condition}
            </Text>
          </Stack>
        </Box>

        {/* Details Section (Humidity & Wind Speed) */}
        <Box padding="var(--ggui-spacing-4, 16px)">
          <Row
            gap="var(--ggui-spacing-4, 16px)"
            justify="around"
            align="center"
          >
            {/* Humidity */}
            <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)" align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
                weight="medium"
              >
                HUMIDITY
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-neutral-900, #111827)"
                weight="bold"
              >
                {humidity}%
              </Text>
            </Stack>

            {/* Wind Speed */}
            <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)" align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
                weight="medium"
              >
                WIND SPEED
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-neutral-900, #111827)"
                weight="bold"
              >
                {windSpeed} mph
              </Text>
            </Stack>
          </Row>
        </Box>

        {/* 5-Day Forecast Section */}
        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-neutral-50, #f9fafb)"
          borderTop="1px solid var(--ggui-color-neutral-200, #e5e7eb)"
        >
          <Stack direction="vertical" gap="var(--ggui-spacing-2, 8px)">
            <Text
              variant="label"
              color="var(--ggui-color-neutral-700, #374151)"
              weight="semibold"
            >
              5-Day Forecast
            </Text>

            {/* Forecast Strip */}
            <Row
              gap="var(--ggui-spacing-2, 8px)"
              justify="between"
              align="stretch"
            >
              {forecast.map((day, index) => {
                const dayKey = day.day + '-' + index;
                return (
                  <Stack
                    key={dayKey}
                    direction="vertical"
                    gap="var(--ggui-spacing-1, 4px)"
                    align="center"
                    justify="center"
                    style={{
                      flex: 1,
                      padding: 'var(--ggui-spacing-2, 8px)',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      background: 'white',
                      border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                      minHeight: '100px',
                    }}
                  >
                    <Text
                      variant="label"
                      color="var(--ggui-color-neutral-700, #374151)"
                      weight="semibold"
                      align="center"
                    >
                      {day.day}
                    </Text>
                    <div style={{ fontSize: '28px', lineHeight: '1' }}>
                      {day.icon}
                    </div>
                    <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)">
                      <Text
                        variant="caption"
                        color="var(--ggui-color-neutral-900, #111827)"
                        weight="bold"
                      >
                        {Math.round(day.high)}°
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        {Math.round(day.low)}°
                      </Text>
                    </Stack>
                  </Stack>
                );
              })}
            </Row>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  highTemp: number;
  lowTemp: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: string;
  forecast?: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();

  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloud')) return '☁️';
  if (lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('storm') || lowerCondition.includes('thunder')) return '⛈️';
  if (lowerCondition.includes('wind')) return '💨';
  if (lowerCondition.includes('fog')) return '🌫️';
  if (lowerCondition.includes('drizzle')) return '🌦️';

  return '🌤️'; // default
};

export default function GeneratedComponent({
