import React from 'react';
import { Card, Stack, Row, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: object[];
}

const getWeatherEmoji = (condition: string): string => {
  const normalized = condition.toLowerCase();

  if (normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('storm')) return '⛈️';
  if (normalized.includes('rain')) return '🌧️';
  if (normalized.includes('drizzle')) return '🌦️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';

  return '🌤️';
};

const formatTemperature = (value: number, unit: string): string => {
  return String(Math.round(value)) + '°' + unit;
};

const getWindUnit = (unit: string): string => {
  return unit === 'F' ? 'mph' : 'km/h';
};

const castForecastItem = (item: object, index: number): ForecastItem => {
  const source = item as Partial<ForecastItem>;
  return {
    day: typeof source.day === 'string' && source.day ? source.day : 'Day ' + String(index + 1),
    condition: typeof source.condition === 'string' ? source.condition : '',
    high: typeof source.high === 'number' ? source.high : 0,
    low: typeof source.low === 'number' ? source.low : 0,
  };
};

export default function GeneratedComponent({
  city = 'City',
  temperature = 0,
  condition = 'Clear',
  humidity = 0,
  windSpeed = 0,
