          >
            Current Weather
          </Text>
          <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)" weight="bold">
            {city}
          </Text>
        </Stack>

        <Row justify="between" align="center" gap={16}>
          <Stack gap={8}>
            <Text
              variant="h1"
              weight="bold"
              color="var(--ggui-color-neutral-900, #111827)"
            >
              {formatTemperature(temperature, unit)}
            </Text>
            <Row gap={8} align="center">
              <Text
                variant="h2"
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {getWeatherEmoji(condition)}
              </Text>
              <Text variant="body" color="var(--ggui-color-neutral-700, #374151)" weight="medium">
                {condition}
              </Text>
            </Row>
          </Stack>

          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Stack gap={12}>
              <Row justify="between" gap={24}>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
